const raw = $input.first().json;

const body = (raw.body && typeof raw.body === 'object' && Object.keys(raw.body).length > 0)
  ? raw.body
  : raw;

const mode = body.mode || body.emailType || 'invite';
const name = body.name || 'Athlete';
const email = body.email || body.toEmail || '';
const phone = body.phone || '';
const appUrl = body.appUrl || (mode === 'planReady'
  ? 'https://airfitworkout.vercel.app/client/dashboard'
  : 'https://airfitworkout.vercel.app/client/login');
const planType = body.planType || 'Workout Plan';

if (!email) {
  throw new Error('Missing email address. Received keys: ' + Object.keys(body).join(', '));
}

function renderShell(eyebrow, bodyHtml, ctaText) {
  return '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>'
    + '<body style="margin:0;padding:0;background:#0d0d0d;font-family:Arial,Helvetica,sans-serif;">'
    + '<table width="100%" cellpadding="0" cellspacing="0" style="background:#0d0d0d;padding:32px 0;"><tr><td align="center">'
    + '<table width="520" cellpadding="0" cellspacing="0" style="background:#111;border-radius:14px;overflow:hidden;border:1px solid #1a1a1a;">'
    + '<tr><td style="background:linear-gradient(135deg,#FF5C1A 0%,#cc2200 100%);padding:36px 32px;text-align:center;">'
    + '<h1 style="color:#fff;font-size:26px;margin:0;letter-spacing:8px;font-weight:900;text-transform:uppercase;">AIRFIT GYM</h1>'
    + '<div style="width:40px;height:3px;background:rgba(255,255,255,0.3);margin:12px auto;border-radius:2px;"></div>'
    + '<p style="color:rgba(255,255,255,0.75);font-size:11px;margin:0;letter-spacing:3px;text-transform:uppercase;">' + eyebrow + '</p>'
    + '</td></tr><tr><td style="padding:32px;">'
    + '<p style="color:#f0f0f0;font-size:16px;font-weight:700;margin:0 0 12px;">Hey ' + name + '!</p>'
    + bodyHtml
    + '<div style="text-align:center;margin:28px 0;"><a href="' + appUrl + '" style="display:inline-block;background:linear-gradient(90deg,#FF5C1A,#cc3300);color:#fff;padding:15px 36px;border-radius:8px;text-decoration:none;font-weight:900;font-size:14px;letter-spacing:2px;text-transform:uppercase;">' + ctaText + '</a></div>'
    + '<div style="background:#0d0d0d;border-radius:10px;padding:18px;border:1px solid #1a1a1a;margin-top:20px;">'
    + '<p style="color:#555;font-size:11px;text-transform:uppercase;letter-spacing:2px;margin:0 0 10px;">LOGIN PHONE</p>'
    + '<p style="color:#888;font-size:13px;margin:0;">Use this phone number in the portal: <strong style="color:#FF5C1A;font-family:monospace;letter-spacing:2px;">' + phone + '</strong></p>'
    + '</div></td></tr><tr><td style="padding:0 32px;"><div style="height:1px;background:linear-gradient(90deg,transparent,#FF5C1A,transparent);"></div></td></tr>'
    + '<tr><td style="background:#0a0a0a;padding:22px 32px;text-align:center;"><p style="color:#FF5C1A;font-size:13px;font-weight:900;margin:0 0 6px;letter-spacing:1px;">Train Smart. Train Hard. Train With AI.</p><p style="color:#2a2a2a;font-size:10px;margin:0;letter-spacing:1px;">AIRFIT GYM</p></td></tr>'
    + '</table></td></tr></table></body></html>';
}

let subject;
let htmlBody;
if (mode === 'planReady') {
  subject = 'Your AirFit plan is ready';
  htmlBody = renderShell(
    'Plan Ready',
    '<p style="color:#aaa;font-size:14px;line-height:1.7;margin:0 0 20px;">Your personalized ' + planType + ' is ready in the AirFit portal. Open your dashboard to view the one-week workout template, exercise videos, progress tracking, diet tools, and calorie log.</p>',
    'Open My Dashboard'
  );
} else {
  subject = "You're Invited to Airfit Gym Training Portal!";
  htmlBody = renderShell(
    'Training Portal Invite',
    '<p style="color:#aaa;font-size:14px;line-height:1.7;margin:0 0 20px;">You have been added to the <strong style="color:#FF5C1A;">AirFit Gym Training Portal</strong>. Log in, fill out the questionnaire, and your one-week reusable workout template with YouTube tutorials will be generated.</p>',
    'Enter Training Portal'
  );
}

return [{ json: {
  toEmail: email,
  subject,
  htmlBody,
  name,
  phone,
  mode
}}];
